import makeWASocket, {
  useMultiFileAuthState,
  DisconnectReason,
  fetchLatestBaileysVersion,
  WASocket,
} from "@whiskeysockets/baileys";
import path from "path";
import { Boom } from "@hapi/boom";
import fs from "fs";

const AUTH_DIR = path.resolve(process.cwd(), "wa_auth");

let sock: WASocket | null = null;
let connectionStatus: "disconnected" | "connecting" | "connected" = "disconnected";
let isInitializing = false;

export async function initializeWhatsApp() {
  if (isInitializing || sock) return;
  isInitializing = true;

  // Only attempt to connect if the auth directory exists and has credentials
  if (!fs.existsSync(AUTH_DIR)) {
    console.warn("[WhatsApp] Admin auth directory not found. WhatsApp features will be disabled. Run 'npx tsx scripts/connect-whatsapp.ts' to pair.");
    isInitializing = false;
    return;
  }

  connectionStatus = "connecting";

  try {
    const { state, saveCreds } = await useMultiFileAuthState(AUTH_DIR);
    const { version, isLatest } = await fetchLatestBaileysVersion();
    console.log(`[WhatsApp] Using WA v${version.join(".")}, isLatest: ${isLatest}`);

    sock = makeWASocket({
      version,
      auth: state,
      printQRInTerminal: false,
    });

    sock.ev.on("creds.update", saveCreds);

    sock.ev.on("connection.update", async (update) => {
      const { connection, lastDisconnect } = update;

      if (connection === "close") {
        const reason = (lastDisconnect?.error as Boom)?.output?.statusCode;
        if (reason === DisconnectReason.loggedOut) {
          console.warn("[WhatsApp] Admin account logged out. Please re-run the pairing script.");
          connectionStatus = "disconnected";
          sock = null;
        } else {
          // Reconnect on non-logout disconnections
          console.log("[WhatsApp] Connection closed, reconnecting...");
          sock = null;
          isInitializing = false;
          setTimeout(initializeWhatsApp, 5000);
        }
      }

      if (connection === "open") {
        console.log("[WhatsApp] ✅ Admin connection established successfully.");
        connectionStatus = "connected";
      }
    });
  } catch (error) {
    console.error("[WhatsApp] Connection error:", error);
    connectionStatus = "disconnected";
    sock = null;
  } finally {
    isInitializing = false;
  }
}

export async function sendWhatsAppMessage(
  phone: string,
  message: string
): Promise<boolean> {
  if (!sock || connectionStatus !== "connected") {
    throw new Error("WhatsApp is not connected");
  }

  try {
    // Normalize phone number: remove +, spaces, dashes
    const cleanPhone = phone.replace(/[^0-9]/g, "");
    const jid = `${cleanPhone}@s.whatsapp.net`;

    await sock.sendMessage(jid, { text: message });
    return true;
  } catch (error) {
    console.error("WhatsApp send error:", error);
    throw error;
  }
}

export function isConnected(): boolean {
  return connectionStatus === "connected" && sock !== null;
}

import cron from "node-cron";
import getDb from "@/lib/db";
import { sendWhatsAppMessage, isConnected, initializeWhatsApp } from "@/lib/whatsapp";

let mainTask: ReturnType<typeof cron.schedule> | null = null;
let isExecuting = false;

async function processQueue() {
  if (isExecuting) return;
  isExecuting = true;

  try {
    const db = getDb();
    const pendingMessages = db
      .prepare(`
        SELECT * FROM queued_messages
        WHERE status = 'pending'
          AND datetime(scheduled_for) <= datetime('now')
        ORDER BY datetime(scheduled_for) ASC
      `)
      .all() as any[];

    if (pendingMessages.length === 0) {
      isExecuting = false;
      return;
    }

    if (!isConnected()) {
      console.log(`[Scheduler] WhatsApp not connected, but have ${pendingMessages.length} pending messages. Attempting reconnect...`);
      initializeWhatsApp();
      isExecuting = false;
      return;
    }

    for (const msg of pendingMessages) {
      try {
        // Send to target phone
        await sendWhatsAppMessage(msg.target_phone, msg.message_text);

        // CC if exists
        if (msg.cc_phone) {
          await new Promise(resolve => setTimeout(resolve, 1000)); // Delay for CC
          const ccPrefix = msg.profile_id ? `[CC for Profile]` : `[CC for Group]`;
          await sendWhatsAppMessage(msg.cc_phone, `${ccPrefix}\n\n${msg.message_text}`);
        }

        // Mark as sent
        db.prepare("UPDATE queued_messages SET status = 'sent' WHERE id = ?").run(msg.id);
        console.log(`[Scheduler] Sent message ${msg.id} to ${msg.target_phone}`);

        // Random delay to avoid spam filters
        await new Promise(resolve => setTimeout(resolve, 2000 + Math.random() * 3000));
      } catch (err) {
        console.error(`[Scheduler] Failed to send message ${msg.id}:`, err);
        db.prepare("UPDATE queued_messages SET status = 'failed' WHERE id = ?").run(msg.id);
      }
    }
  } catch (error) {
    console.error("[Scheduler] Error processing queue:", error);
  } finally {
    isExecuting = false;
  }
}

export function loadAllSchedules() {
  try {
    // Initialize WhatsApp connection in the background
    initializeWhatsApp();

    // Start single minute-by-minute worker
    if (mainTask) {
      mainTask.stop();
    }

    mainTask = cron.schedule("* * * * *", () => {
      processQueue();
    });

    console.log(`[Scheduler] Started main message queue worker (runs every minute).`);
  } catch (error) {
    console.error("[Scheduler] Failed to start queue worker:", error);
  }
}

export function getActiveTaskCount(): number {
  return mainTask ? 1 : 0;
}

import { NextRequest, NextResponse } from "next/server";
import { auth } from "@/lib/auth";
import getDb from "@/lib/db";
import { randomUUID } from "crypto";
import { getAiConfig, generateCompletion, buildBulkMessagesPrompt } from "@/lib/ai";

// GET: List all queued messages (optionally filter by profile_id or group_id)
export async function GET(req: NextRequest) {
  const session = await auth();
  if (!session?.user?.id) return NextResponse.json({ error: "Unauthorized" }, { status: 401 });

  const { searchParams } = new URL(req.url);
  const profileId = searchParams.get("profile_id");
  const groupId = searchParams.get("group_id");

  const db = getDb();
  let query = `
    SELECT qm.*, hp.title AS plan_title
    FROM queued_messages qm
    LEFT JOIN health_plans hp ON qm.plan_id = hp.id
    WHERE qm.user_id = ?
  `;
  const params: unknown[] = [session.user.id];

  if (profileId) { query += " AND qm.profile_id = ?"; params.push(profileId); }
  if (groupId) { query += " AND qm.group_id = ?"; params.push(groupId); }
  query += " ORDER BY datetime(qm.scheduled_for) ASC";

  const messages = db.prepare(query).all(...params);
  return NextResponse.json(messages);
}

// POST: Generate and queue messages via AI
export async function POST(req: NextRequest) {
  const session = await auth();
  if (!session?.user?.id) return NextResponse.json({ error: "Unauthorized" }, { status: 401 });

  try {
    const {
      profile_id,
      group_id,
      target_phone,
      cc_phone,
      days = 7,
      schedule_time = "08:00",
      custom_context,
      recipient_name,
      plan_content,
      plan_id,
    } = await req.json();

    if (!target_phone || !plan_content) {
      return NextResponse.json({ error: "target_phone and plan_content are required" }, { status: 400 });
    }

    // Generate messages with AI
    const config = getAiConfig(session.user.id);
    const prompt = buildBulkMessagesPrompt(plan_content, recipient_name || "Friend", days, custom_context);

    let messages: string[] = [];
    try {
      const raw = await generateCompletion(config, [{ role: "user", content: prompt }]);
      // Extract JSON array from response
      const jsonMatch = raw.match(/\[[\s\S]*\]/);
      if (jsonMatch) {
        messages = JSON.parse(jsonMatch[0]);
      }
    } catch {
      return NextResponse.json({ error: "AI failed to generate messages. Check your LLM connection." }, { status: 500 });
    }

    if (!Array.isArray(messages) || messages.length === 0) {
      return NextResponse.json({ error: "AI returned invalid message format." }, { status: 500 });
    }

    // Schedule each message on consecutive days at schedule_time
    const db = getDb();
    let linkedPlanId: string | null = null;

    if (plan_id) {
      const linkedPlan = db.prepare(`
        SELECT hp.id, hp.profile_id, hp.group_id
        FROM health_plans hp
        LEFT JOIN profiles p ON hp.profile_id = p.id
        LEFT JOIN profile_groups g ON hp.group_id = g.id
        WHERE hp.id = ? AND (p.user_id = ? OR g.user_id = ?)
      `).get(plan_id, session.user.id, session.user.id) as { id: string; profile_id?: string | null; group_id?: string | null } | undefined;

      if (!linkedPlan) {
        return NextResponse.json({ error: "Invalid plan_id" }, { status: 400 });
      }

      if (profile_id && linkedPlan.profile_id !== profile_id) {
        return NextResponse.json({ error: "plan_id does not belong to this profile" }, { status: 400 });
      }

      if (group_id && linkedPlan.group_id !== group_id) {
        return NextResponse.json({ error: "plan_id does not belong to this group" }, { status: 400 });
      }

      linkedPlanId = linkedPlan.id;
    }

    const [hour, minute] = schedule_time.split(":").map(Number);
    const insertedMessages = [];

    for (let i = 0; i < Math.min(messages.length, days); i++) {
      const scheduledFor = new Date();
      scheduledFor.setDate(scheduledFor.getDate() + i);
      scheduledFor.setHours(hour, minute, 0, 0);

      const id = randomUUID();
      db.prepare(`
        INSERT INTO queued_messages (id, user_id, profile_id, group_id, plan_id, target_phone, cc_phone, message_text, scheduled_for, status)
        VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, 'pending')
      `).run(
        id, session.user.id,
        profile_id || null, group_id || null,
        linkedPlanId,
        target_phone, cc_phone || null,
        messages[i],
        scheduledFor.toISOString()
      );

      insertedMessages.push({ id, message_text: messages[i], scheduled_for: scheduledFor.toISOString(), status: "pending" });
    }

    return NextResponse.json({ created: insertedMessages.length, messages: insertedMessages });
  } catch (error) {
    console.error("Messages API error:", error);
    return NextResponse.json({ error: "Failed to generate messages" }, { status: 500 });
  }
}

