  async function refreshAll() {
    setLoading(true);
    try {
      const [plansData, msgs, settings] = await Promise.all([
        fetch(planApiPath).then((r) => r.json()),
        fetch(`/api/messages?${queryParam}`).then((r) => r.json()),
