import makeWASocket, { useMultiFileAuthState, fetchLatestBaileysVersion } from "@whiskeysockets/baileys";
import path from "path";
import fs from "fs";
import pino from "pino";
import { randomUUID } from "crypto";

const AUTH_DIR = path.resolve(process.cwd(), "wa_auth");

async function sendTestNotification(phone: string, message: string) {
  if (!fs.existsSync(AUTH_DIR)) {
    console.error("❌ No WhatsApp auth found. Run 'npx tsx scripts/connect-whatsapp.ts login' first.");
    process.exit(1);
  }

  console.log(`📤 Sending test notification to ${phone}...`);

  const { state, saveCreds } = await useMultiFileAuthState(AUTH_DIR);
  const { version } = await fetchLatestBaileysVersion();

  const sock = makeWASocket({
    version,
    auth: state,
    printQRInTerminal: false,
    logger: pino({ level: "silent" }) as any,
  });

  sock.ev.on("creds.update", saveCreds);

  await new Promise<void>((resolve, reject) => {
    const timeout = setTimeout(() => reject(new Error("Connection timeout")), 15000);

    sock.ev.on("connection.update", async (update) => {
      const { connection } = update;
      if (connection === "open") {
        clearTimeout(timeout);
        try {
          const cleanPhone = phone.replace(/[^0-9]/g, "");
          const jid = `${cleanPhone}@s.whatsapp.net`;
          await sock.sendMessage(jid, { text: message });
          console.log(`✅ Message sent successfully to ${phone}!`);
          resolve();
        } catch (err) {
          reject(err);
        }
      } else if (connection === "close") {
        clearTimeout(timeout);
        reject(new Error("Connection closed before message could be sent"));
      }
    });
  });

  // Give time for message delivery, then exit
  await new Promise(resolve => setTimeout(resolve, 2000));
  process.exit(0);
}

// Also expose a way to manually flush pending messages from DB
async function flushPending() {
  const db = (await import("better-sqlite3")).default(
    path.resolve(process.cwd(), "healthforge.db")
  );

  const pending = db.prepare(
    `SELECT * FROM queued_messages
     WHERE status = 'pending'
       AND datetime(scheduled_for) <= datetime('now')
     ORDER BY datetime(scheduled_for) ASC`
  ).all() as any[];

  if (pending.length === 0) {
    console.log("✅ No pending messages to send.");
    process.exit(0);
  }

  console.log(`Found ${pending.length} pending message(s). Sending...`);

  const { state, saveCreds } = await useMultiFileAuthState(AUTH_DIR);
  const { version } = await fetchLatestBaileysVersion();

  const sock = makeWASocket({
    version,
    auth: state,
    printQRInTerminal: false,
    logger: pino({ level: "silent" }) as any,
  });
  sock.ev.on("creds.update", saveCreds);

  await new Promise<void>((resolve, reject) => {
    const timeout = setTimeout(() => reject(new Error("Connection timeout")), 15000);
    sock.ev.on("connection.update", async ({ connection }) => {
      if (connection === "open") {
        clearTimeout(timeout);
        for (const msg of pending) {
          try {
            const jid = `${msg.target_phone.replace(/[^0-9]/g, "")}@s.whatsapp.net`;
            await sock.sendMessage(jid, { text: msg.message_text });
            db.prepare("UPDATE queued_messages SET status = 'sent' WHERE id = ?").run(msg.id);
            console.log(`✅ Sent to ${msg.target_phone}: ${msg.message_text.substring(0, 60)}...`);
            if (msg.cc_phone) {
              const ccJid = `${msg.cc_phone.replace(/[^0-9]/g, "")}@s.whatsapp.net`;
              await sock.sendMessage(ccJid, { text: `[CC]\n\n${msg.message_text}` });
              console.log(`   📋 CC sent to ${msg.cc_phone}`);
            }
            await new Promise(r => setTimeout(r, 1500));
          } catch (err) {
            db.prepare("UPDATE queued_messages SET status = 'failed' WHERE id = ?").run(msg.id);
            console.error(`❌ Failed to send ${msg.id}:`, err);
          }
        }
        resolve();
      } else if (connection === "close") {
        clearTimeout(timeout);
        reject(new Error("Connection closed"));
      }
    });
  });

  await new Promise(resolve => setTimeout(resolve, 2000));
  process.exit(0);
}

function parseScheduleTime(raw: string): Date | null {
  const trimmed = raw.trim();
  if (!trimmed) return null;

  // Accept: 2026-04-23T21:45, 2026-04-23 21:45, or full ISO.
  const isoLike = trimmed.includes(" ") ? trimmed.replace(" ", "T") : trimmed;
  const withSeconds = isoLike.length === 16 ? `${isoLike}:00` : isoLike;
  const dt = new Date(withSeconds);
  return Number.isNaN(dt.getTime()) ? null : dt;
}

async function queueTestNotification(phone: string, when: string, message: string) {
  const scheduledFor = parseScheduleTime(when);
  if (!scheduledFor) {
    console.error("❌ Invalid time format. Use YYYY-MM-DDTHH:mm (e.g. 2026-04-23T21:45).");
    process.exit(1);
  }

  const db = (await import("better-sqlite3")).default(
    path.resolve(process.cwd(), "healthforge.db")
  );

  const user = db.prepare("SELECT id FROM users ORDER BY created_at DESC LIMIT 1").get() as { id: string } | undefined;
  if (!user?.id) {
    console.error("❌ No user found in DB. Please sign up/login once before queuing test notifications.");
    process.exit(1);
  }

  const id = randomUUID();
  db.prepare(`
    INSERT INTO queued_messages (id, user_id, target_phone, message_text, scheduled_for, status)
    VALUES (?, ?, ?, ?, ?, 'pending')
  `).run(
    id,
    user.id,
    phone.replace(/[^0-9]/g, ""),
    message,
    scheduledFor.toISOString()
  );

  console.log("✅ Test notification queued.");
  console.log(`   ID: ${id}`);
  console.log(`   Phone: ${phone}`);
  console.log(`   Scheduled (local): ${scheduledFor.toLocaleString()}`);
  console.log("   Tip: run `npx tsx scripts/test-notification.ts flush` to force immediate dispatch.");
  process.exit(0);
}

// CLI
const command = process.argv[2];
if (command === "flush") {
  flushPending().catch(e => { console.error(e); process.exit(1); });
} else if (command === "send") {
  const phone = process.argv[3];
  const message = process.argv[4];

  if (!phone || !message) {
    console.log("Usage: npx tsx scripts/test-notification.ts send <phone> '<message>'");
    process.exit(1);
  }

  sendTestNotification(phone, message).catch(e => { console.error("❌ Error:", e.message); process.exit(1); });
} else if (command === "queue") {
  const phone = process.argv[3];
  const when = process.argv[4];
  const message = process.argv[5];

  if (!phone || !when || !message) {
    console.log("Usage: npx tsx scripts/test-notification.ts queue <phone> <YYYY-MM-DDTHH:mm> '<message>'");
    process.exit(1);
  }

  queueTestNotification(phone, when, message).catch(e => { console.error("❌ Error:", e.message); process.exit(1); });
} else {
  // Backward-compatible shorthand:
  //   <phone> "<message>"            => immediate send
  //   <phone> <time> "<message>"     => queue in DB for scheduler test
  const phone = process.argv[2];
  const maybeSecondArg = process.argv[3];
  const maybeThirdArg = process.argv[4];

  if (!phone || !maybeSecondArg) {
    console.log("Usage:");
    console.log("  Send now: npx tsx scripts/test-notification.ts send <phone> '<message>'");
    console.log("  Queue for time: npx tsx scripts/test-notification.ts queue <phone> <YYYY-MM-DDTHH:mm> '<message>'");
    console.log("  Flush due queue: npx tsx scripts/test-notification.ts flush");
    console.log("\nBackward compatible:");
    console.log("  npx tsx scripts/test-notification.ts <phone> '<message>'");
    console.log("  npx tsx scripts/test-notification.ts <phone> <YYYY-MM-DDTHH:mm> '<message>'");
    process.exit(1);
  }

  if (maybeThirdArg) {
    queueTestNotification(phone, maybeSecondArg, maybeThirdArg).catch(e => { console.error("❌ Error:", e.message); process.exit(1); });
  } else {
    sendTestNotification(phone, maybeSecondArg).catch(e => { console.error("❌ Error:", e.message); process.exit(1); });
  }
}

